  tenant_id uuid NOT NULL DEFAULT (((auth.jwt() -> 'app_metadata'::text) ->> 'tenant_id'::text))::uuid,
  apprentice_profile_id uuid NOT NULL,
  site_id uuid,
  focus text,
  start_date date NOT NULL,
  end_date date,
  outcome_notes text,
  imported_at timestamp with time zone,
  imported_from text,
  intake_id uuid,
  schema_version text,
  created_at timestamp with time zone NOT NULL DEFAULT now(),
  CONSTRAINT rotations_pkey PRIMARY KEY (rotation_id)
);

CREATE TABLE IF NOT EXISTS app_data.schedule_change_logs (
  log_id uuid NOT NULL DEFAULT gen_random_uuid(),
  tenant_id uuid NOT NULL DEFAULT (((auth.jwt() -> 'app_metadata'::text) ->> 'tenant_id'::text))::uuid,
  schedule_id uuid,
  staff_id uuid,
  site_id uuid,
  change_type text NOT NULL,
  old_value jsonb,
  new_value jsonb,
  changed_by_user_id uuid,
  changed_at timestamp with time zone NOT NULL DEFAULT now(),
  reason text,
  imported_at timestamp with time zone,
  imported_from text,
  intake_id uuid,
  schema_version text,
  CONSTRAINT schedule_change_type_check CHECK ((change_type = ANY (ARRAY['created'::text, 'staff_changed'::text, 'site_changed'::text, 'date_changed'::text, 'hours_changed'::text, 'status_changed'::text, 'deleted'::text, 'reassigned'::text]))),
  CONSTRAINT schedule_change_logs_pkey PRIMARY KEY (log_id)
);

CREATE TABLE IF NOT EXISTS app_data.schedule_entries (
  schedule_id uuid NOT NULL DEFAULT gen_random_uuid(),
  tenant_id uuid NOT NULL DEFAULT (((auth.jwt() -> 'app_metadata'::text) ->> 'tenant_id'::text))::uuid,
  staff_id uuid NOT NULL,
  site_id uuid NOT NULL,
  date date NOT NULL,
  hours_planned numeric NOT NULL,
  hours_actual numeric,
  shift text DEFAULT 'day'::text,
  task text,
  status text DEFAULT 'planned'::text,
  leave_type text,
  notes text,
  supervisor_id uuid,
  imported_at timestamp with time zone,
  imported_from text,
  intake_id uuid,
  schema_version text,
  created_at timestamp with time zone NOT NULL DEFAULT now(),
  updated_at timestamp with time zone NOT NULL DEFAULT now(),
  created_by uuid,
  updated_by uuid,
  CONSTRAINT schedule_entries_leave_type_enum_check CHECK (((leave_type IS NULL) OR (leave_type = ANY (ARRAY['annual'::text, 'sick'::text, 'personal'::text, 'rdo'::text, 'tafe'::text, 'unpaid'::text, 'public_holiday'::text, 'other'::text])))),
  CONSTRAINT schedule_entries_shift_enum_check CHECK (((shift IS NULL) OR (shift = ANY (ARRAY['day'::text, 'evening'::text, 'night'::text, 'weekend'::text, 'afterhours'::text])))),
  CONSTRAINT schedule_entries_status_enum_check CHECK (((status IS NULL) OR (status = ANY (ARRAY['planned'::text, 'confirmed'::text, 'in_progress'::text, 'completed'::text, 'cancelled'::text, 'no_show'::text])))),
  CONSTRAINT schedule_entries_pkey PRIMARY KEY (schedule_id)
);

CREATE TABLE IF NOT EXISTS app_data.scope_template (
  template_id uuid NOT NULL DEFAULT gen_random_uuid(),
  tenant_id uuid NOT NULL DEFAULT (((auth.jwt() -> 'app_metadata'::text) ->> 'tenant_id'::text))::uuid,
  name text NOT NULL,
  category text,
  body text NOT NULL,
