  active boolean NOT NULL DEFAULT true,
  imported_at timestamp with time zone,
  imported_from text,
  intake_id uuid,
  schema_version text,
  created_at timestamp with time zone NOT NULL DEFAULT now(),
  updated_at timestamp with time zone NOT NULL DEFAULT now(),
  created_by uuid,
  updated_by uuid,
  CONSTRAINT scope_template_pkey PRIMARY KEY (template_id)
);

CREATE TABLE IF NOT EXISTS app_data.site_diaries (
  site_diary_id uuid NOT NULL DEFAULT gen_random_uuid(),
  tenant_id uuid NOT NULL DEFAULT (((auth.jwt() -> 'app_metadata'::text) ->> 'tenant_id'::text))::uuid,
  site_id uuid NOT NULL,
  diary_date date NOT NULL,
  shift_type text,
  start_time time without time zone,
  end_time time without time zone,
  supervisor_name text,
  supervisor_user_id uuid,
  subcontractor text,
  weather jsonb NOT NULL DEFAULT '{}'::jsonb,
  work_areas jsonb NOT NULL DEFAULT '[]'::jsonb,
  delays jsonb NOT NULL DEFAULT '[]'::jsonb,
  incidents jsonb NOT NULL DEFAULT '[]'::jsonb,
  visitors jsonb NOT NULL DEFAULT '[]'::jsonb,
  materials_received text,
  equipment_status text,
  notes text,
  attendance jsonb NOT NULL DEFAULT '[]'::jsonb,
  photo_paths jsonb NOT NULL DEFAULT '[]'::jsonb,
  status text NOT NULL DEFAULT 'draft'::text,
  submitted_at timestamp with time zone,
  submitted_by_user_id uuid,
