CREATE TABLE IF NOT EXISTS app_data.skills_ratings (
  skills_rating_id uuid NOT NULL DEFAULT gen_random_uuid(),
  tenant_id uuid NOT NULL DEFAULT (((auth.jwt() -> 'app_metadata'::text) ->> 'tenant_id'::text))::uuid,
  apprentice_profile_id uuid NOT NULL,
  skill_name text NOT NULL,
  rating smallint NOT NULL,
  rated_by_user_id uuid,
  rated_at timestamp with time zone NOT NULL DEFAULT now(),
  notes text,
  imported_at timestamp with time zone,
  imported_from text,
  intake_id uuid,
  schema_version text,
