  CONSTRAINT skills_ratings_pkey PRIMARY KEY (skills_rating_id)
);

CREATE TABLE IF NOT EXISTS app_data.swms (
  swms_id uuid NOT NULL DEFAULT gen_random_uuid(),
  tenant_id uuid NOT NULL DEFAULT (((auth.jwt() -> 'app_metadata'::text) ->> 'tenant_id'::text))::uuid,
  external_id text,
  version text,
  site_id uuid NOT NULL,
  activity character varying(200) NOT NULL,
  high_risk_categories jsonb,
  hazards jsonb,
  ppe_required jsonb,
  permits_required jsonb,
  tools_plant jsonb,
  training_competency jsonb,
  emergency_procedures text,
  prepared_by_user_id uuid,
  prepared_by text NOT NULL,
  prepared_at timestamp with time zone NOT NULL,
  reviewed_by text,
  reviewed_at timestamp with time zone,
  valid_from date,
  valid_until date,
  signatures jsonb,
  attachments jsonb,
  status text NOT NULL DEFAULT 'draft'::text,
  source text,
  raw_extract text,
  imported_at timestamp with time zone,
  imported_from text,
  intake_id uuid,
  schema_version text,
  created_at timestamp with time zone NOT NULL DEFAULT now(),
  updated_at timestamp with time zone NOT NULL DEFAULT now(),
  created_by uuid,
  updated_by uuid,
  CONSTRAINT swms_source_enum_check CHECK (((source IS NULL) OR (source = ANY (ARRAY['cards_mobile'::text, 'import_spreadsheet'::text, 'capture_pdf'::text, 'capture_photo'::text, 'capture_email'::text, 'manual_entry'::text])))),
  CONSTRAINT swms_status_enum_check CHECK (((status IS NULL) OR (status = ANY (ARRAY['draft'::text, 'active'::text, 'expired'::text, 'superseded'::text, 'archived'::text])))),
