);

CREATE TABLE IF NOT EXISTS app_data.tafe_calendars (
  tafe_calendar_id uuid NOT NULL DEFAULT gen_random_uuid(),
  tenant_id uuid NOT NULL DEFAULT (((auth.jwt() -> 'app_metadata'::text) ->> 'tenant_id'::text))::uuid,
  year smallint NOT NULL,
  trade text,
  year_level smallint,
  term_dates jsonb NOT NULL DEFAULT '[]'::jsonb,
  public_holidays jsonb NOT NULL DEFAULT '[]'::jsonb,
  imported_at timestamp with time zone,
  imported_from text,
  intake_id uuid,
  schema_version text,
  created_at timestamp with time zone NOT NULL DEFAULT now(),
  CONSTRAINT tafe_year_check CHECK (((year >= 2020) AND (year <= 2099))),
  CONSTRAINT tafe_year_level_check CHECK (((year_level IS NULL) OR ((year_level >= 1) AND (year_level <= 4)))),
  CONSTRAINT tafe_calendars_pkey PRIMARY KEY (tafe_calendar_id)
);

CREATE TABLE IF NOT EXISTS app_data.tenant_app_configs (
