  updated_at timestamp with time zone NOT NULL DEFAULT now(),
  CONSTRAINT tender_nomination_status_check CHECK ((status = ANY (ARRAY['proposed'::text, 'confirmed'::text, 'withdrawn'::text, 'clashed'::text]))),
  CONSTRAINT tender_nominations_pkey PRIMARY KEY (nomination_id)
);

CREATE TABLE IF NOT EXISTS app_data.tender_review_decisions (
