);

CREATE TABLE IF NOT EXISTS app_data.tenders (
  tender_id uuid NOT NULL DEFAULT gen_random_uuid(),
  tenant_id uuid NOT NULL DEFAULT (((auth.jwt() -> 'app_metadata'::text) ->> 'tenant_id'::text))::uuid,
  tender_number text,
  external_id text,
  title text NOT NULL,
  client_name text,
  customer_id uuid,
  stage text NOT NULL DEFAULT 'watch'::text,
  estimated_value_cents bigint,
  close_date date,
  department text,
  estimator_user_id uuid,
  scope_summary text,
  notes text,
  imported_at timestamp with time zone,
  imported_from text,
  intake_id uuid,
  schema_version text,
  created_at timestamp with time zone NOT NULL DEFAULT now(),
