  CONSTRAINT tenders_pkey PRIMARY KEY (tender_id)
);

CREATE TABLE IF NOT EXISTS app_data.timesheets (
  timesheet_id uuid NOT NULL DEFAULT gen_random_uuid(),
  tenant_id uuid NOT NULL DEFAULT (((auth.jwt() -> 'app_metadata'::text) ->> 'tenant_id'::text))::uuid,
  staff_id uuid NOT NULL,
  site_id uuid,
  schedule_id uuid,
  date date NOT NULL,
  start_time time without time zone,
  end_time time without time zone,
  hours numeric(6,2) NOT NULL DEFAULT 0,
  break_minutes integer NOT NULL DEFAULT 0,
  shift text,
  task text,
  status text NOT NULL DEFAULT 'draft'::text,
  submitted_at timestamp with time zone,
  approved_at timestamp with time zone,
  approved_by_user_id uuid,
  paid_at timestamp with time zone,
  notes text,
  imported_at timestamp with time zone,
  imported_from text,
  intake_id uuid,
  schema_version text,
  created_at timestamp with time zone NOT NULL DEFAULT now(),
  updated_at timestamp with time zone NOT NULL DEFAULT now(),
  created_by uuid,
  updated_by uuid,
  CONSTRAINT timesheet_hours_non_negative CHECK ((hours >= (0)::numeric)),
  CONSTRAINT timesheet_shift_valid CHECK (((shift IS NULL) OR (shift = ANY (ARRAY['day'::text, 'night'::text, 'split'::text, 'arvo'::text])))),
  CONSTRAINT timesheet_status_check CHECK ((status = ANY (ARRAY['draft'::text, 'submitted'::text, 'approved'::text, 'rejected'::text, 'paid'::text]))),
  CONSTRAINT timesheets_pkey PRIMARY KEY (timesheet_id)
);

