-- Grants, RLS, tenant isolation, updated_at trigger

GRANT ALL ON app_data.apprentice_profiles TO service_role;
ALTER TABLE app_data.apprentice_profiles ENABLE ROW LEVEL SECURITY;
DO $$ BEGIN
  IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_schema='app_data' AND table_name='apprentice_profiles' AND column_name='tenant_id') THEN
    EXECUTE 'DROP POLICY IF EXISTS apprentice_profiles_tenant_isolation ON app_data.apprentice_profiles';
    EXECUTE 'CREATE POLICY apprentice_profiles_tenant_isolation ON app_data.apprentice_profiles FOR ALL TO authenticated USING (tenant_id = ((auth.jwt() -> ''app_metadata'' ->> ''tenant_id''))::uuid) WITH CHECK (tenant_id = ((auth.jwt() -> ''app_metadata'' ->> ''tenant_id''))::uuid)';
  END IF;
  IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_schema='app_data' AND table_name='apprentice_profiles' AND column_name='updated_at') THEN
    EXECUTE 'DROP TRIGGER IF EXISTS apprentice_profiles_touch_updated_at ON app_data.apprentice_profiles';
    EXECUTE 'CREATE TRIGGER apprentice_profiles_touch_updated_at BEFORE UPDATE ON app_data.apprentice_profiles FOR EACH ROW EXECUTE FUNCTION app_data.touch_updated_at()';
  END IF;
END $$;

