  END IF;
  IF EXISTS (SELECT 1 FROM information_schema.columns WHERE table_schema='app_data' AND table_name='assets' AND column_name='updated_at') THEN
    EXECUTE 'DROP TRIGGER IF EXISTS assets_touch_updated_at ON app_data.assets';
    EXECUTE 'CREATE TRIGGER assets_touch_updated_at BEFORE UPDATE ON app_data.assets FOR EACH ROW EXECUTE FUNCTION app_data.touch_updated_at()';
